'use client';

import { SingleImageDrop } from '@/components/dropzone/single-image-drop';

interface AvatarDropzoneSquareProps {
    className?: string;
    onFileSelect?: (file: File | null) => void;
    maxSize?: number;
    defaultImage?: string;
}

export function AvatarDropzoneSquare({
    className,
    onFileSelect,
    maxSize = 5 * 1024 * 1024,
    defaultImage,
}: AvatarDropzoneSquareProps) {
    return (
        <SingleImageDrop
            variant="square"
            onFile={onFileSelect || (() => {})}
            maxSize={maxSize}
            preview={defaultImage}
            className={className}
        />
    );
}
